#include <algorithm>

string mergeAlternately(string word1, string word2) {
    string merged;
    int len1 = word1.length();
    int len2 = word2.length();

    if (len1 > len2) {
        std::copy(word1.begin(), word1.end(), std::back_inserter(merged));
        std::copy(word2.begin(), word2.end(), merged.begin() + len1);
    } else {
        std::copy(word2.begin(), word2.end(), std::back_inserter(merged));
        std::copy(word1.begin(), word1.end(), merged.begin() + len2);
    }

    return merged;
}
